import requests

def get_token():
    r = requests.post(
        'https://login.microsoftonline.com/YOUR_TENANT_ID/oauth2/v2.0/token',
        data={
            'grant_type': 'client_credentials',
            'client_id': 'YOUR_APP_ID',
            'client_secret': 'YOUR_SECRET',
            'scope': 'https://graph.microsoft.com/.default',
        }
    )
    return r.json()['access_token']

token = get_token()
headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}

# Get phishing-resistant built-in strength
strengths = requests.get(
    'https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies',
    headers=headers
).json().get('value', [])

# Create a custom Authentication Strength: WHfB + FIDO2 only
custom_strength = {
    'displayName': 'WHfB and FIDO2 Only',
    'description': 'Requires Windows Hello for Business or FIDO2 security key',
    'allowedCombinations': [
        'windowsHelloForBusiness',
        'fido2'
    ]
}
custom_resp = requests.post(
    'https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies',
    headers=headers, json=custom_strength
)
custom_strength_id = custom_resp.json().get('id')

# CA policy: require WHfB or FIDO2 for Azure admin portals
admin_ca = {
    'displayName': 'Require WHfB or FIDO2 -- Azure Admin',
    'state': 'enabledForReportingButNotEnforced',
    'conditions': {
        'users': {
            'includeRoles': [
                '62e90394-69f5-4237-9190-012177145e10',  # Global Admin
                '194ae4cb-b126-40b2-bd5b-6091b380977d',  # Security Admin
            ],
            'excludeGroups': ['BREAK-GLASS-GROUP-ID']
        },
        'applications': {
            'includeApplications': ['797f4846-ba00-4fd7-ba43-dac1f8f63013']  # Azure portal
        }
    },
    'grantControls': {
        'operator': 'OR',
        'authenticationStrength': {'id': custom_strength_id}
    }
}
resp = requests.post(
    'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies',
    headers=headers, json=admin_ca
)
print(f'Policy created: {resp.json().get("id")}')

import requests
from collections import Counter
from datetime import datetime, timedelta, timezone

def get_token():
    r = requests.post(
        'https://login.microsoftonline.com/YOUR_TENANT_ID/oauth2/v2.0/token',
        data={
            'grant_type': 'client_credentials',
            'client_id': 'YOUR_APP_ID',
            'client_secret': 'YOUR_SECRET',
            'scope': 'https://graph.microsoft.com/.default',
        }
    )
    return r.json()['access_token']

def analyse_signin_methods(token, days=7):
    headers = {'Authorization': f'Bearer {token}'}
    since = (datetime.now(timezone.utc) - timedelta(days=days)).strftime('%Y-%m-%dT%H:%M:%SZ')

    resp = requests.get(
        'https://graph.microsoft.com/v1.0/auditLogs/signIns'
        f'?$filter=createdDateTime ge {since} and status/errorCode eq 0'
        '&$select=userPrincipalName,authenticationMethodsUsed,authenticationDetails'
        '&$top=999',
        headers={**headers, 'ConsistencyLevel': 'eventual'}
    )
    signins = resp.json().get('value', [])

    method_counter = Counter()
    for s in signins:
        for detail in s.get('authenticationDetails', []):
            method = detail.get('authenticationMethod', 'Unknown')
            method_counter[method] += 1

    print(f'Auth methods used in last {days} days ({len(signins)} sign-ins):')
    for method, count in method_counter.most_common():
        pct = 100 * count // len(signins) if signins else 0
        print(f'  {method:<45} {count:>6} ({pct:>3}%)')

    whfb = [s for s in signins
            if any('Windows Hello' in str(d.get('authenticationMethod',''))
                   for d in s.get('authenticationDetails', []))]
    print(f'WHfB sign-ins: {len(whfb)} of {len(signins)}')

token = get_token()
analyse_signin_methods(token, days=7)
